 13	} from '@patternfly/react-core';
 14	import { ExclamationCircleIcon, ExclamationTriangleIcon } from '@patternfly/react-icons';
 15	import * as React from 'react';
 16	import { useTranslation } from 'react-i18next';
 17	import { Status } from '../../api/loki';
 18	import { getBuildInfo, getLimits, getLokiMetrics, getStatus } from '../../api/routes';
 19	import { ContextSingleton } from '../../utils/context';
 20	import {
 21	  getGenericHTTPError,
 22	  LokiClientError,
 23	  LokiResponseError,
 24	  PromDisabledMetrics,
 25	  PromMissingLabels,
 26	  PromUnsupported,
 27	  StructuredError
 28	} from '../../utils/errors';
 29	import { ErrorSuggestions } from './error-suggestions';
 30	import './error.css';
 31	import { SecondaryAction } from './secondary-action';
 32	import { StatusTexts } from './status-texts';
 33	
 34	export type Size = 's' | 'm' | 'l';
 35	
 36	enum LokiInfo {
 37	  Hidden,
 38	  Metrics,
 39	  Build,
 40	  Limits
 41	}
 42	
 43	export interface ErrorProps {
 44	  title: string;
 45	  error: string | StructuredError;
 46	}
 47	
 48	export const ErrorComponent: React.FC<ErrorProps> = ({ title, error }) => {
 49	  const { t } = useTranslation('plugin__netobserv-plugin');
 50	  const [lokiLoading, setLokiLoading] = React.useState(
 51	    LokiClientError.isTypeOf(error) || LokiResponseError.isTypeOf(error)
 52	  );
 53	  const [statusLoading, setStatusLoading] = React.useState(true);
 54	  const [status, setStatus] = React.useState<Status | undefined>();
 55	  const [statusError, setStatusError] = React.useState<string | undefined>();
 56	  const [infoName, setInfoName] = React.useState<string | undefined>();
 57	  const [info, setInfo] = React.useState<string | undefined>();
 58	
 59	  const updateInfo = React.useCallback(
 60	    (type: LokiInfo) => {
 61	      setLokiLoading(true);
 62	
 63	      switch (type) {
 64	        case LokiInfo.Build:
 65	          setInfoName(t('Build info'));
 66	          getBuildInfo()
 67	            .then(data => setInfo(JSON.stringify(data, null, 2)))
 68	            .catch(err => {
 69	              setInfo(getGenericHTTPError(err));
 70	            })
 71	            .finally(() => {
 72	              setLokiLoading(false);
 73	            });
 74	          break;
 75	        case LokiInfo.Limits:
 76	          setInfoName(t('Configuration limits'));
 77	          getLimits()
 78	            .then(data => setInfo(JSON.stringify(data, null, 2)))
 79	            .catch(err => {
 80	              setInfo(getGenericHTTPError(err));
 81	            })
 82	            .finally(() => {
 83	              setLokiLoading(false);
 84	            });
 85	          break;
 86	        case LokiInfo.Metrics:
 87	          setInfoName(t('Metrics'));
 88	          getLokiMetrics()
 89	            .then(data => setInfo(data))
 90	            .catch(err => {
 91	              setInfo(getGenericHTTPError(err));
 92	            })
 93	            .finally(() => {
 94	              setLokiLoading(false);
 95	            });
 96	          break;
 97	        case LokiInfo.Hidden:
 98	        default:
 99	          setInfoName(undefined);
100	          setInfo(undefined);
101	          setLokiLoading(false);
102	          break;
103	      }
104	    },
105	    [t]
106	  );
107	
108	  React.useEffect(() => {
109	    //jest crashing on getStatus not defined so we need to ensure the function is defined here
110	    if (!getStatus) {
111	      return;
112	    }
113	
114	    getStatus(ContextSingleton.getForcedNamespace())
115	      .then(status => {
116	        console.info('status result', status);
117	        setStatus(status);
118	        setStatusError(undefined);
119	      })
120	      .catch(err => {
121	        const errorMessage = getGenericHTTPError(err);
122	        console.error(errorMessage);
123	        setStatusError(errorMessage);
124	        setStatus(undefined);
125	      })
126	      .finally(() => {
127	        setStatusLoading(false);
128	      });
129	  }, []);
130	
131	  // Set different error icon depending on the severity (e.g. configuration error is less severe)
132	  const isCritical =
133	    !PromUnsupported.isTypeOf(error) && !PromDisabledMetrics.isTypeOf(error) && !PromMissingLabels.isTypeOf(error);
134	
135	  return (
136	    <div id="netobserv-error-container">
137	      <EmptyState data-test="error-state">
138	        <EmptyStateHeader
139	          titleText={title}
140	          headingLevel="h2"
141	          icon={<EmptyStateIcon icon={isCritical ? ExclamationCircleIcon : ExclamationTriangleIcon} />}
142	        />
143	        <EmptyStateBody className="error-body">
144	          <Text className={isCritical ? 'netobserv-error-message' : ''} component={TextVariants.p}>
145	            {String(error)}
146	          </Text>
147	          <TextContent className="error-text-content">
148	            {typeof error !== 'string' && <ErrorSuggestions error={error} compact={false} />}
149	            {status && <StatusTexts status={status} />}
150	            {statusError && (
151	              <Text component={TextVariants.blockquote}>
152	                {t('Check for errors in health dashboard. Status endpoint is returning: {{statusError}}', {
153	                  statusError
154	                })}
155	              </Text>
156	            )}
157	          </TextContent>
158	        </EmptyStateBody>
159	        <SecondaryAction
160	          showMetrics={() => updateInfo(LokiInfo.Metrics)}
161	          showBuildInfo={() => updateInfo(LokiInfo.Build)}
162	          showConfigLimits={() => updateInfo(LokiInfo.Limits)}
163	        />
164	      </EmptyState>
165	      {lokiLoading || statusLoading ? (
166	        <Bullseye data-test="loading-errors">
167	          <Spinner size="xl" />
168	        </Bullseye>
169	      ) : (
170	        info && (
171	          <TextContent>
172	            <Text component={TextVariants.h4}>{infoName}</Text>
173	            <ClipboardCopy
174	              isCode
175	              isExpanded
176	              hoverTip={t('Copy')}
177	              clickTip={t('Copied')}
178	              variant={ClipboardCopyVariant.expansion}
179	            >
180	              {info}
181	            </ClipboardCopy>
182	          </TextContent>
183	        )
184	      )}
185	    </div>
186	  );
187	};
188	
189	export default ErrorComponent;

